async function slowScrollFrame(frame: Frame, direction: 'down' | 'up'): Promise<void> {
  const step = direction === 'down' ? 450 : -450;
  for (let i = 0; i < 10; i += 1) {
    try {
      await withTimeout(frame.evaluate((d) => window.scrollBy(0, d), step), 1500, `scroll(${direction})#${i + 1}`);
    } catch {
      break;
    }
    await frame.page().waitForTimeout(180);
  }
}

async function readDigitsFromField(locator: Locator): Promise<string> {
  await locator.scrollIntoViewIfNeeded();
  await flashElement(locator, 'READ');
  logAction('READ', await describeElement(locator));
  const raw = await locator.evaluate((el) => {
    if (el instanceof HTMLInputElement || el instanceof HTMLTextAreaElement) return el.value ?? '';
    return (el.textContent ?? '').trim();
  });
  return (raw ?? '').replace(/\D+/g, '');
}

async function readDigitsFromValue(locator: Locator): Promise<string> {
  await locator.scrollIntoViewIfNeeded();
  await flashElement(locator, 'READ:value');
  logAction('READ:value', await describeElement(locator));
  const raw = await locator.evaluate((el) => {
    const anyEl = el as unknown as { value?: unknown };
    return typeof anyEl.value === 'string' ? anyEl.value : '';
  });
  return (raw ?? '').replace(/\D+/g, '');
}

