test.describe.serial('SAC_166839 (VCOM): Contratos -> Registra Grupo Contrato', () => {
  test.beforeAll(() => {
    fs.mkdirSync(OUT_DIR, { recursive: true });
    fs.mkdirSync(VIDEO_DIR, { recursive: true });
    const header = [
      `# Relatorio ${SAC_NUMERO} (VCOM)`,
      '',
      `Gerado em: ${nowIso()}`,
      '',
      '| Contrato | Grupo | Status | Executado em |',
      '| --- | --- | --- | --- |',
      '',
    ].join('\n');
    fs.writeFileSync(REPORT_PATH, header, { encoding: 'utf-8' });
  });

  test.afterEach(async ({}, testInfo) => {
    const contrato = testInfo.annotations.find((a) => a.type === 'contrato')?.description ?? extractContratoFromTitle(testInfo.title);
    const grupo = testInfo.annotations.find((a) => a.type === 'grupo')?.description ?? '';
    const status = testInfo.status;

    fs.appendFileSync(REPORT_PATH, `| ${contrato} | ${grupo} | ${status} | ${nowIso()} |\n`, { encoding: 'utf-8' });

    if (!contrato || contrato === 'unknown') return;

    const dst = path.resolve(VIDEO_DIR, `${contrato}.webm`);
    fs.mkdirSync(VIDEO_DIR, { recursive: true });

    const rootsToSearch = [
      testInfo.outputDir,
      path.dirname(testInfo.outputDir),
      path.dirname(path.dirname(testInfo.outputDir)),
      path.resolve(OUT_DIR, 'pw-headed-results-sac166839-vcom'),
      path.resolve(OUT_DIR, 'pw-results-sac166839-vcom'),
      path.resolve(REPO_ROOT, 'test-results'),
    ];

    const seen = new Set<string>();
    const findVideo = (root: string): string => {
      if (!root || seen.has(root)) return '';
      seen.add(root);
      if (!fs.existsSync(root)) return '';

      const stack: string[] = [root];
      while (stack.length) {
        const dir = stack.pop()!;
        let entries: fs.Dirent[] = [];
        try {
          entries = fs.readdirSync(dir, { withFileTypes: true });
        } catch {
          continue;
        }
        for (const ent of entries) {
          const full = path.join(dir, ent.name);
          if (ent.isDirectory()) {
            // prune node_modules-like paths just in case
            if (/node_modules/i.test(ent.name)) continue;
            stack.push(full);
            continue;
          }
          if (!ent.isFile()) continue;
          if (ent.name.toLowerCase() !== 'video.webm') continue;
          if (!full.includes(contrato)) continue;
          return full;
        }
      }
      return '';
    };

    let src = '';
    for (const r of rootsToSearch) {
      src = findVideo(r);
      if (src) break;
    }
    if (!src) {
      const fromVideo = testInfo.video?.path();
      if (fromVideo && fs.existsSync(fromVideo)) src = fromVideo;
