function nowIso(): string {
  return new Date().toISOString();
}

function extractContratoFromTitle(title: string): string {
  const m = title.match(/\b\d{8,}\b/);
  return m ? m[0] : 'unknown';
}

test.describe.serial(`SAC_166839 (VCOM) via request: ${REQUEST.sac.nome}`, () => {
  test.beforeAll(() => {
    fs.mkdirSync(OUT_DIR, { recursive: true });
    fs.mkdirSync(VIDEO_DIR, { recursive: true });
    const header = [
      `# Relatorio ${SAC_NUMERO} (VCOM)`,
      '',
      `Gerado em: ${nowIso()}`,
      '',
      '| Contrato | Grupo | Status | Executado em |',
      '| --- | --- | --- | --- |',
      '',
    ].join('\n');
    fs.writeFileSync(REPORT_PATH, header, { encoding: 'utf-8' });
  });

  test.afterEach(async ({}, testInfo) => {
    const contrato = testInfo.annotations.find((a) => a.type === 'contrato')?.description ?? extractContratoFromTitle(testInfo.title);
    const grupo = testInfo.annotations.find((a) => a.type === 'grupo')?.description ?? '';
