      await step(page, `20: Fechar tela Registra Grupo Contrato (contrato ${contrato})`, async () => {
        const closed = await closeTopmostKendoWindow(page);
        if (!closed) {
          const closeAny = page.locator('[aria-label="Close"]:visible, button:has-text("Close"):visible').last();
          if (await closeAny.count()) await clickCentered(closeAny, 'FECHAR: Close(any)');
