async function waitForFrameByUrlPart(page: Page, urlPart: string, timeoutMs: number): Promise<Frame> {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    const frames = page.frames();
    const found = frames.find((f) => (f.url() ?? '').toLowerCase().includes(urlPart.toLowerCase()));
    if (found) return found;
    await page.waitForTimeout(250);
  }
  throw new Error(`Frame nao encontrado: url contem '${urlPart}' (timeout ${timeoutMs}ms)`);
}

async function waitForContratoDetalhesFrame(page: Page, timeoutMs: number): Promise<Frame> {
  const deadline = Date.now() + timeoutMs;

  while (Date.now() < deadline) {
    const frames = page.frames();
    for (const frame of frames) {
      try {
        const nomeGrupo = frame.locator(`#${ID_NOME_GRUPO}`).first();
        if (await nomeGrupo.count()) return frame;
        const grupoRow = frame.getByRole('row', { name: /Grupo Contrato/i }).first();
        if (await grupoRow.count()) return frame;
      } catch {
        // ignore detached frames
      }
    }

    for (const frame of frames) {
      try {
        const ind = frame.locator(`#${ID_IND_ADMIN}`).first();
        if (await ind.count()) return frame;
      } catch {
        // ignore detached frames
      }
    }

    for (const frame of frames) {
      try {
        const limpar = frame.locator(`#${ID_ACAO_LIMPAR}`).first();
        if (await limpar.count()) return frame;
      } catch {
        // ignore detached frames
      }
    }

    await page.waitForTimeout(250);
  }

  throw new Error(`Frame de detalhes do contrato nao encontrado (timeout ${timeoutMs}ms)`);
}

async function waitForFrameWithSelector(page: Page, selector: string, timeoutMs: number): Promise<Frame> {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    for (const frame of page.frames()) {
      try {
        if (await frame.locator(selector).first().count()) return frame;
      } catch {
        // ignore detached frames
      }
    }
    await page.waitForTimeout(250);
  }
  throw new Error(`Frame nao encontrado: seletor '${selector}' (timeout ${timeoutMs}ms)`);
}

async function findFirstInFrames(page: Page, selector: string): Promise<Locator | null> {
  for (const frame of page.frames()) {
    try {
      const loc = frame.locator(selector).first();
      if (await loc.count()) return loc;
    } catch {
      // ignore detached frames
    }
  }
  return null;
}

async function forceClickByDataModuloFuncao(page: Page, dm: string): Promise<void> {
  const selector = `[data-modulo-funcao="${dm}"]`;
  const loc = await findFirstInFrames(page, selector);
  if (!loc) throw new Error(`Item do menu nao encontrado: ${selector}`);
  await loc.evaluate((el) => {
    (el as HTMLElement).scrollIntoView({ block: 'center', inline: 'center' });
    (el as HTMLElement).click();
  });
}

async function slowScrollFrame(frame: Frame, direction: 'down' | 'up'): Promise<void> {
  const step = direction === 'down' ? 450 : -450;
  for (let i = 0; i < 10; i += 1) {
    try {
      await withTimeout(frame.evaluate((d) => window.scrollBy(0, d), step), 1500, `scroll(${direction})#${i + 1}`);
    } catch {
      break;
    }
    await frame.page().waitForTimeout(180);
  }
}

async function readDigitsFromValue(locator: Locator): Promise<string> {
  await locator.scrollIntoViewIfNeeded();
  await flashElement(locator, 'READ:value');
  logAction('READ:value', await describeElement(locator));
  const raw = await locator.evaluate((el) => {
    const anyEl = el as unknown as { value?: unknown };
    return typeof anyEl.value === 'string' ? anyEl.value : '';
  });
  return (raw ?? '').replace(/\D+/g, '');
}

async function readDigitsFromContratoFrame(frame: Frame): Promise<string> {
  const byId = frame.locator(`#${ID_NOME_GRUPO}`).first();
  if (await byId.count()) return readDigitsFromValue(byId);

  const grupoRow = frame.getByRole('row', { name: /Grupo Contrato/i }).first();
  if (await grupoRow.count()) {
    const tb = grupoRow.getByRole('textbox').first();
    if (await tb.count()) return readDigitsFromValue(tb);
  }

  return '';
}

async function findContratoField(page: Page): Promise<Locator> {
  const frames = page.frames();
  for (const frame of frames) {
    const byId = frame.locator(`#${ID_NUM_CONTRATO}`).first();
    if (await byId.count()) return byId;
  }
  for (const frame of frames) {
    const row = frame.getByRole('row', { name: /Contrato/i }).first();
    if (!(await row.count())) continue;
    const tb = row.getByRole('textbox').first();
    if (await tb.count()) return tb;
  }
  for (const frame of frames) {
    const byName = frame.locator('input[id*="contrato" i], input[name*="contrato" i]').first();
    if (await byName.count()) return byName;
  }
  throw new Error(`Campo do contrato nao encontrado: id="${ID_NUM_CONTRATO}"`);
}

async function fillContratoWithFallback(page: Page, contrato: string): Promise<void> {
  const field = await findContratoField(page);

  await clickCentered(field);
  try {
    await field.fill(contrato, { timeout: 8000 });
  } catch {
    // ignore
  }

  const current = await field.inputValue().catch(() => '');
  if (!current || current.replace(/\D+/g, '') !== contrato.replace(/\D+/g, '')) {
    await field.fill('', { timeout: 8000 }).catch(() => {});
    await field.pressSequentially(contrato, { delay: 90 });
  }

  await field.press('Tab').catch(() => {});
}

async function closeTopmostKendoWindow(page: Page): Promise<boolean> {
  const closeBtn = page.locator('a.k-window-action.k-link:visible, .k-window-action.k-link:visible').last();
  if (await closeBtn.count()) {
    await clickCentered(closeBtn);
    return true;
  }
  const alt = page.getByRole('button', { name: /Fechar|Close/i }).last();
  if (await alt.count()) {
    await clickCentered(alt);
    return true;
  }

  await page.keyboard.press('Escape').catch(() => {});
  // eslint-disable-next-line no-console
  console.log(`[${currentStepName}] WARN: botao de fechar nao encontrado; enviado ESC.`);
  return false;
}

async function clickLimparInContratoFrame(frame: Frame): Promise<void> {
  const byId = frame.locator(`#${ID_ACAO_LIMPAR}`).first();
  if (await byId.count()) {
    await clickCentered(byId);
    return;
  }

  const img = frame.getByRole('img', { name: /Limpar/i }).first();
  if (await img.count()) {
    await clickCentered(img);
    return;
  }

  const btn = frame.getByRole('button', { name: /Limpar/i }).first();
  if (await btn.count()) {
    await clickCentered(btn);
    return;
  }
}

async function findGrupoField(page: Page): Promise<Locator> {
  const frames = page.frames();
  for (const frame of frames) {
    const byId = frame.locator(`#${ID_COD_GRUPO}`).first();
    if (await byId.count()) return byId;
  }
  throw new Error(`Campo do grupo nao encontrado: id="${ID_COD_GRUPO}"`);
}

async function clickContinuar(page: Page): Promise<void> {
  const frames = page.frames();
  for (const frame of frames) {
    const img = frame.getByRole('img', { name: /Continuar/i }).first();
    if (await img.count()) {
      await clickCentered(img);
      return;
    }
  }

  for (const frame of frames) {
    const btn = frame.getByRole('button', { name: /Continuar/i }).first();
    if (await btn.count()) {
      await clickCentered(btn);
      return;
    }
  }

  for (const frame of frames) {
    const submit = frame.locator('input[type="submit" i][value*="continuar" i]').first();
    if (await submit.count()) {
      await clickCentered(submit);
      return;
    }
  }

  throw new Error("Botao/acao 'Continuar' nao encontrado");
}

async function waitForAnyFrameText(page: Page, pattern: RegExp, timeoutMs: number): Promise<void> {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    for (const frame of page.frames()) {
      try {
        const hit = frame.getByText(pattern).first();
        if (await hit.count()) return;
      } catch {
        // ignore detached frames
      }
    }
    await page.waitForTimeout(250);
  }
  throw new Error(`Texto nao encontrado em nenhum frame: ${String(pattern)} (timeout ${timeoutMs}ms)`);
}

test.setTimeout(20 * 60 * 1000);
test.use({ video: 'on' });

const SAC_NUMERO = REQUEST.sac.numero;
const OUT_DIR = path.resolve(REPO_ROOT, 'tests', SAC_NUMERO);
const VIDEO_DIR = path.resolve(OUT_DIR, 'videos');
const REPORT_PATH = path.resolve(OUT_DIR, `${SAC_NUMERO}_report.md`);

function nowIso(): string {
  return new Date().toISOString();
}

function extractContratoFromTitle(title: string): string {
  const m = title.match(/\b\d{8,}\b/);
  return m ? m[0] : 'unknown';
}

test.describe.serial(`SAC_166839 (VCOM) via request v2: ${REQUEST.sac.nome}`, () => {
  test.beforeAll(() => {
    fs.mkdirSync(OUT_DIR, { recursive: true });
    fs.mkdirSync(VIDEO_DIR, { recursive: true });
    const header = [
      `# Relatorio ${SAC_NUMERO} (VCOM)`,
      '',
      `Gerado em: ${nowIso()}`,
      '',
      '| Contrato | Grupo | Status | Executado em |',
      '| --- | --- | --- | --- |',
      '',
    ].join('\n');
    fs.writeFileSync(REPORT_PATH, header, { encoding: 'utf-8' });
  });

  test.afterEach(async ({}, testInfo) => {
    const contrato = testInfo.annotations.find((a) => a.type === 'contrato')?.description ?? extractContratoFromTitle(testInfo.title);
    const grupo = testInfo.annotations.find((a) => a.type === 'grupo')?.description ?? '';
    const status = testInfo.status;

    fs.appendFileSync(REPORT_PATH, `| ${contrato} | ${grupo} | ${status} | ${nowIso()} |\n`, { encoding: 'utf-8' });

    if (!contrato || contrato === 'unknown') return;

    const dst = path.resolve(VIDEO_DIR, `${contrato}.webm`);
    fs.mkdirSync(VIDEO_DIR, { recursive: true });

    const rootsToSearch = [
      testInfo.outputDir,
      path.dirname(testInfo.outputDir),
      path.dirname(path.dirname(testInfo.outputDir)),
      path.resolve(OUT_DIR, 'pw-results-sac166839-vcom'),
      path.resolve(REPO_ROOT, 'test-results'),
    ];

    const seen = new Set<string>();
    const findVideo = (root: string): string => {
      if (!root || seen.has(root)) return '';
      seen.add(root);
      if (!fs.existsSync(root)) return '';

      const stack: string[] = [root];
      while (stack.length) {
        const dir = stack.pop()!;
        let entries: fs.Dirent[] = [];
        try {
          entries = fs.readdirSync(dir, { withFileTypes: true });
        } catch {
          continue;
        }
        for (const ent of entries) {
          const full = path.join(dir, ent.name);
          if (ent.isDirectory()) {
            if (/node_modules/i.test(ent.name)) continue;
            stack.push(full);
            continue;
          }
          if (!ent.isFile()) continue;
          if (ent.name.toLowerCase() !== 'video.webm') continue;
          if (!full.includes(contrato)) continue;
          return full;
        }
      }
      return '';
    };

    let src = '';
    for (const r of rootsToSearch) {
      src = findVideo(r);
      if (src) break;
    }
    if (!src) {
      const fromVideo = testInfo.video?.path();
      if (fromVideo && fs.existsSync(fromVideo)) src = fromVideo;
    }
    if (!src) return;

    try {
      fs.copyFileSync(src, dst);
    } catch {
      // ignore
    }
  });

  for (const contrato of CONTRATOS) {
    test(`Contrato ${contrato}`, async ({ page }, testInfo) => {
      testInfo.annotations.push({ type: 'contrato', description: contrato });

      const menu = new FuncoesAcessoMenu(page, { log: (msg) => logAction('MENU', msg) });
      let grupo = '';
      let contratoFrame: Frame | null = null;

      await installClickHighlighter(page);

      await step(page, '1-4: Login', async () => {
        await login(page);
        await assertAreaLogada(page);
      });

      await step(page, `5-6: Validar area logada (contrato ${contrato})`, async () => {
        await assertAreaLogada(page);
      });

      await step(page, `7: Abrir menu Alteracao (${MENU_ALTERACAO}) (contrato ${contrato})`, async () => {
        try {
          await menu.abrirMenu(MENU_ALTERACAO);
        } catch {
          await ensureMenuOpen(page);
          try {
            await menu.abrirMenu(MENU_ALTERACAO);
          } catch {
            await forceClickByDataModuloFuncao(page, MENU_ALTERACAO);
          }
        }
      });

      await step(page, `8-10: Informar num_contrato (contrato ${contrato})`, async () => {
        await waitForFrameByUrlPart(page, FRAME_ALTERACAO, 30_000);
        await fillContratoWithFallback(page, contrato);
      });

      await step(
        page,
        `11: Aguardar carregar ${FRAME_DETALHES} (max ${AGUARDAR_CONTRATO_CARREGAR_S}s) (contrato ${contrato})`,
        async () => {
          // eslint-disable-next-line no-console
          console.log(`[${currentStepName}] WAIT: carregamento tela contrato (${FRAME_DETALHES}/dom).`);
          const byUrl = waitForFrameByUrlPart(page, FRAME_DETALHES, AGUARDAR_CONTRATO_CARREGAR_S * 1000).catch(() => null);
          const byDom = waitForContratoDetalhesFrame(page, AGUARDAR_CONTRATO_CARREGAR_S * 1000).then((f) => {
            contratoFrame = f;
            return f;
          });
          await Promise.race([byDom, byUrl]);
        },
        AGUARDAR_CONTRATO_CARREGAR_S * 1000 + 2000,
      );

      await step(page, `12: Scroll ate o fim do frame (contrato ${contrato})`, async () => {
        const f = contratoFrame ?? (await waitForContratoDetalhesFrame(page, 15_000));
        contratoFrame = f;
        // eslint-disable-next-line no-console
        console.log(`[${currentStepName}] SCROLL: down`);
        await slowScrollFrame(f, 'down');
      });

      await step(page, `13: Foco em ${ID_IND_ADMIN} (contrato ${contrato})`, async () => {
        const indAdmin = await findFirstInFrames(page, `#${ID_IND_ADMIN}`);
        if (indAdmin) {
          await showCentered(indAdmin, `SHOW: ${ID_IND_ADMIN}`);
        } else {
          // eslint-disable-next-line no-console
          console.log(`[${currentStepName}] WARN: #${ID_IND_ADMIN} nao encontrado.`);
        }
      });

      await step(page, `14: Ler grupo (value) em ${ID_NOME_GRUPO} (contrato ${contrato})`, async () => {
        const frame = contratoFrame ?? (await waitForContratoDetalhesFrame(page, 15_000));
        contratoFrame = frame;
        grupo = await readDigitsFromContratoFrame(frame);
        if (grupo) {
          const loc = await findFirstInFrames(page, `#${ID_NOME_GRUPO}`);
          if (loc) await showCentered(loc, `SHOW: ${ID_NOME_GRUPO}`);
        }

        testInfo.annotations.push({ type: 'grupo', description: grupo });

        if (!grupo) {
          // eslint-disable-next-line no-console
          console.log(`[${currentStepName}] Grupo vazio/ausente em #${ID_NOME_GRUPO}; seguindo para o proximo contrato.`);
        }
      });

      await step(page, `15: Scroll ate o inicio do frame (contrato ${contrato})`, async () => {
        const f = contratoFrame ?? (await waitForContratoDetalhesFrame(page, 15_000));
        contratoFrame = f;
        // eslint-disable-next-line no-console
        console.log(`[${currentStepName}] SCROLL: up`);
        await slowScrollFrame(f, 'up');
      });

      await step(page, `16: Limpar e fechar tela de contrato (contrato ${contrato})`, async () => {
        const limparFrame = await waitForFrameWithSelector(page, `#${ID_ACAO_LIMPAR}`, 15_000);
        await clickLimparInContratoFrame(limparFrame);
        await closeTopmostKendoWindow(page);
      });

      if (!grupo) {
        // eslint-disable-next-line no-console
        console.log(`[${currentStepName}] INFO: sem grupo, pulando passos 18-20.`);
        return;
      }

      await step(page, `18: Abrir menu Registra Grupo Contrato (${MENU_REGISTRA}) (contrato ${contrato})`, async () => {
        try {
          await menu.abrirMenu(MENU_REGISTRA);
        } catch {
          await ensureMenuOpen(page);
          await menu.abrirMenu(MENU_REGISTRA);
        }
      });

      await step(page, `19: Informar grupo e continuar (grupo ${grupo})`, async () => {
        await waitForFrameByUrlPart(page, FRAME_REGISTRA, 30_000);

        const grupoInput = await findGrupoField(page);
        await clickCentered(grupoInput, `FOCO: ${ID_COD_GRUPO}`);
        await grupoInput.fill('').catch(() => {});
        await grupoInput.pressSequentially(grupo, { delay: 75 });

        const readBack = await grupoInput.inputValue().catch(() => '');
        const readDigits = (readBack ?? '').replace(/\D+/g, '');
        // eslint-disable-next-line no-console
        console.log(`[${currentStepName}] VALUE: ${ID_COD_GRUPO}="${readBack}" digits="${readDigits}" expectedGrupo="${grupo}"`);
        if (readDigits && readDigits === contrato.replace(/\D+/g, '')) {
          throw new Error(`Campo ${ID_COD_GRUPO} ficou com numero do contrato (${readDigits}) em vez do grupo (${grupo}).`);
        }
        if (grupo && readDigits !== grupo) {
          throw new Error(`Campo ${ID_COD_GRUPO} nao recebeu o grupo esperado. esperado="${grupo}" obtido="${readDigits}"`);
        }

        await clickContinuar(page);

        await waitForAnyFrameText(page, /Registra Grupo Contrato/i, 30_000);
        await waitForAnyFrameText(page, /Adicionar Contrato|Nome do Contratante|Contratos do Grupo/i, 30_000);
      });

      await step(page, `20: Fechar tela Registra Grupo Contrato (contrato ${contrato})`, async () => {
        const closed = await closeTopmostKendoWindow(page);
        if (!closed) {
          const closeAny = page.locator('[aria-label="Close"]:visible, button:has-text("Close"):visible').last();
          if (await closeAny.count()) await clickCentered(closeAny, 'FECHAR: Close(any)');
        }
      });
    });
  }
